from fastcore.utils import * 
from torch import nn
import torch.nn.functional as F
import torch
from typing import Tuple, List, Dict, Any

# %% ../../../nbs/02b_models.vision.lenets.ipynb #5b64a343
class MNISTCNN(nn.Module):
    def __init__(self, 
                 img_size: Tuple[int, int, int]= (1, 28, 28), 
                 hidden_dim: int=512,
                 num_classes: int= 10):
        
        super(MNISTCNN, self).__init__()
        in_channels, h, w = img_size    
        self.hidden_dim = hidden_dim

        self.conv1 = nn.Sequential(
            nn.Conv2d(in_channels, 32, kernel_size=5, stride=1, padding=2),
            nn.ReLU(inplace=True),
            nn.MaxPool2d(kernel_size=2, stride=2)
        )

        self.conv2 = nn.Sequential(
            nn.Conv2d(32, 64, kernel_size=5, stride=1, padding=2),
            nn.ReLU(inplace=True),
            nn.MaxPool2d(kernel_size=2, stride=2)
        )

        final_size = h // 2 // 2
        self.fc1 = nn.Linear(64 * final_size * final_size, hidden_dim)
        self.fc2 = nn.Sequential(
            nn.Dropout(0.5),
            nn.Linear(hidden_dim, num_classes),
        )

    def forward(self, x):
        out = self.conv1(x)
        out = self.conv2(out)
        out = torch.flatten(out, 1)
        out = self.fc1(out)
        out = self.fc2(out)
        return out

    

