import torch
import torch.nn as nn
import numpy as np

class CIFAR10CNNBackbone(nn.Module):
    def __init__(self, 
                 img_size: Tuple[int, int, int]= (3, 32, 32), 
                 hidden_dim: int=512):
        
        super(CIFAR10CNNBackbone, self).__init__()
        in_channels, h, w = img_size
        self.hidden_dim = hidden_dim

        self.conv1 = nn.Sequential(
            nn.Conv2d(in_channels, 32, kernel_size=3, stride=1, padding=1),
            nn.ReLU(inplace=True),
            nn.MaxPool2d(kernel_size=2, stride=2)
        )
        self.conv2 = nn.Sequential(
            nn.Conv2d(32, 64, kernel_size=3, stride=1, padding=1),
            nn.ReLU(inplace=True),
            nn.MaxPool2d(kernel_size=2, stride=2)
        )
        self.conv3 = nn.Sequential(
            nn.Conv2d(64, 128, kernel_size=3, stride=1, padding=1),
            nn.ReLU(inplace=True),
            nn.MaxPool2d(kernel_size=2, stride=2)
        )

        final_size = h // 2 // 2 // 2  # 3 pool layers divide the size by 2 three times
        self.fc1 = nn.Sequential(nn.Linear(128 * final_size * final_size, hidden_dim),
                                 nn.ReLU(inplace=True)
                                 )


    def forward(self, x):
        out = self.conv1(x)
        out = self.conv2(out)
        out = self.conv3(out)
        out = torch.flatten(out, 1)
        out = self.fc1(out)
        return out



# %% ../../../nbs/02b_models.vision.lenets.ipynb #307e6a21
class CIFAR10CNN(nn.Module):
    def __init__(self, 
                 img_size: Tuple[int, int, int]= (3, 32, 32), 
                 hidden_dim: int=512,
                 num_classes: int= 10):
        
        super(CIFAR10CNN, self).__init__()
        self.hidden_dim = hidden_dim
        self.backbone = CIFAR10CNNBackbone(img_size, hidden_dim)
        self.head = nn.Linear(hidden_dim, num_classes)
        

    def forward(self, x):
        out = self.backbone(x)
        out = self.head(out)
        return out

