class FedAvgCNNBackbone(nn.Module):
    def __init__(self, 
                 img_size: Tuple[int, int, int]= (3, 32, 32), 
                 hidden_dim: int=512):
        super().__init__()

        in_channels, h, w = img_size
        self.hidden_dim = hidden_dim
        self.conv1 = nn.Sequential(
            nn.Conv2d(in_channels,
                      32,
                      kernel_size=5,
                      padding=0,
                      stride=1,
                      bias=True),
            nn.ReLU(inplace=True), 
            nn.MaxPool2d(kernel_size=(2, 2))
        )
        self.conv2 = nn.Sequential(
            nn.Conv2d(32,
                      64,
                      kernel_size=5,
                      padding=0,
                      stride=1,
                      bias=True),
            nn.ReLU(inplace=True), 
            nn.MaxPool2d(kernel_size=(2, 2))
        )

        def compute_dim(h, w):
            h = (h - 4) // 2  # After conv1 and pool
            w = (w - 4) // 2
            h = (h - 4) // 2  # After conv2 and pool
            w = (w - 4) // 2
            return 64 * h * w


        dim = compute_dim(h, w)
        self.fc1 = nn.Sequential(
            nn.Linear(dim, hidden_dim), 
            nn.ReLU(inplace=True)
        )

    def forward(self, x):
        out = self.conv1(x)
        out = self.conv2(out)
        out = torch.flatten(out, 1)
        out = self.fc1(out)
        return out

# %% ../../../nbs/02b_models.vision.lenets.ipynb #aa99f8e8
class FedAvgCNN(nn.Module):
    def __init__(self, 
                 img_size: Tuple[int, int, int]= (3, 32, 32), 
                 hidden_dim: int=512,
                 num_classes: int= 10):
        super().__init__()

        self.hidden_dim = hidden_dim
        self.backbone = FedAvgCNNBackbone(img_size= img_size, hidden_dim= hidden_dim)
        self.head = nn.Linear(hidden_dim, num_classes)

    def forward(self, x):
        x = self.backbone(x)
        x = self.head(x)
        return x

